import{_ as o,C as i,o as e,c as p,a5 as n,b as r,w as a,a as l,E,a4 as A}from"./chunks/framework.sOZL8giL.js";const m=JSON.parse('{"title":"可观测性","description":"","frontmatter":{},"headers":[],"relativePath":"07-生产实践/01-可观测性.md","filePath":"07-生产实践/01-可观测性.md","lastUpdated":1774181700000}'),d={name:"07-生产实践/01-可观测性.md"};function B(c,t,h,g,b,u){const s=i("Mermaid");return e(),p("div",null,[t[2]||(t[2]=n('<h1 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 7 模块的第 1 章。</p></blockquote><p>Trace/Metrics/Logs 三层可观测性——Trace 即反馈，没有 Trace 就没有改进方向。</p><hr><h2 id="为什么需要可观测性" tabindex="-1">为什么需要可观测性 <a class="header-anchor" href="#为什么需要可观测性" aria-label="Permalink to &quot;为什么需要可观测性&quot;">​</a></h2><p>Agent 系统是概率性的、多步骤的、可能长时间运行的。传统软件的可观测性（日志、监控、告警）仍然需要，但 Agent 还需要额外的维度。</p><p>传统软件可观测性关注：服务是否正常、响应时间是否达标、错误率是多少。Agent 可观测性还需要关注：Agent 在想什么、做了什么决策、为什么这样做、哪里失败了、Token 消耗了多少。</p><p>没有可观测性，Agent 就是黑盒。出了问题你不知道是 Prompt 的问题、工具的问题、还是模型的问题。LangChain 证明了 Trace 是整个改进闭环的核心信号——很多所谓&quot;模型不够聪明&quot;的问题其实是系统没有在合适的时机把正确的上下文交给模型。</p><hr><h2 id="三层架构" tabindex="-1">三层架构 <a class="header-anchor" href="#三层架构" aria-label="Permalink to &quot;三层架构&quot;">​</a></h2>',10)),(e(),r(A,null,{default:a(()=>[E(s,{id:"mermaid-28",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E7%B3%BB%E7%BB%9F%5D%20--%3E%20B%5BTrace%20%E9%93%BE%E8%B7%AF%E8%BF%BD%E8%B8%AA%3Cbr%2F%3E%E5%AE%8C%E6%95%B4%E6%89%A7%E8%A1%8C%E8%B7%AF%E5%BE%84%3Cbr%2F%3E%E9%A3%9E%E6%9C%BA%E9%BB%91%E5%8C%A3%E5%AD%90%5D%0A%20%20%20%20A%20--%3E%20C%5BMetrics%20%E6%8C%87%E6%A0%87%3Cbr%2F%3E%E8%81%9A%E5%90%88%E9%87%8F%E5%8C%96%E6%95%B0%E6%8D%AE%3Cbr%2F%3E%E8%B6%8B%E5%8A%BF%E4%BB%AA%E8%A1%A8%E6%9D%BF%5D%0A%20%20%20%20A%20--%3E%20D%5BLogs%20%E6%97%A5%E5%BF%97%3Cbr%2F%3E%E7%BB%93%E6%9E%84%E5%8C%96%E4%BA%8B%E4%BB%B6%E8%AE%B0%E5%BD%95%3Cbr%2F%3EJSON%E6%A0%BC%E5%BC%8F%E5%8F%AF%E6%9F%A5%E8%AF%A2%5D%0A%20%20%20%20B%20--%3E%20E%5B%E8%B0%83%E8%AF%95%3A%20%E5%AE%9A%E4%BD%8D%E5%A4%B1%E8%B4%A5%E6%AD%A5%E9%AA%A4%5D%0A%20%20%20%20B%20--%3E%20F%5B%E6%94%B9%E8%BF%9B%3A%20%E5%88%86%E6%9E%90%E6%88%90%E5%8A%9F%2F%E5%A4%B1%E8%B4%A5%E6%A8%A1%E5%BC%8F%5D%0A%20%20%20%20B%20--%3E%20G%5B%E5%AE%A1%E8%AE%A1%3A%20%E5%90%88%E8%A7%84%E5%92%8C%E5%AE%89%E5%85%A8%5D%0A%20%20%20%20B%20--%3E%20H%5B%E6%88%90%E6%9C%AC%E5%88%86%E6%9E%90%3A%20Token%E6%B6%88%E8%80%97%5D%0A%20%20%20%20C%20--%3E%20I%5B%E5%91%8A%E8%AD%A6%3A%20%E6%8C%87%E6%A0%87%E5%BC%82%E5%B8%B8%E8%A7%A6%E5%8F%91%5D%0A%20%20%20%20C%20--%3E%20J%5B%E5%BD%92%E5%9B%A0%3A%20%E5%93%AA%E4%B8%AAAgent%E6%9C%80%E7%83%A7%E9%92%B1%5D%0A%20%20%20%20D%20--%3E%20K%5B%E8%BF%BD%E8%B8%AA%3A%20Session%2FAgent%2FTask%5D%0A%20%20%20%20E%20--%3E%20L%5BTrace%20%E5%8D%B3%E5%8F%8D%E9%A6%88%3Cbr%2F%3E%E6%94%B9%E8%BF%9B%E9%97%AD%E7%8E%AF%E7%9A%84%E6%A0%B8%E5%BF%83%E4%BF%A1%E5%8F%B7%5D%0A%20%20%20%20F%20--%3E%20L%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=n(`<blockquote><p>💡 <strong>图解：</strong> Trace 是飞机黑匣子——Agent 死了你得知道它在第几步出了什么问题，没有 Trace 就没有改进方向。</p></blockquote><h3 id="trace-链路追踪" tabindex="-1">Trace（链路追踪） <a class="header-anchor" href="#trace-链路追踪" aria-label="Permalink to &quot;Trace（链路追踪）&quot;">​</a></h3><p>记录 Agent 的完整执行路径——每一次思考、每一次工具调用、每一次观察。像飞机的黑匣子，精确记录 Agent 在每一步做了什么。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Trace 示例：</span></span>
<span class="line"><span>[时间: 2024-01-15 10:30:01] [Agent: research] [Step: 1]</span></span>
<span class="line"><span>  Thought: 需要搜索竞品信息</span></span>
<span class="line"><span>  Action: web_search(query=&quot;OpenAI competitors 2024&quot;)</span></span>
<span class="line"><span>  Observation: 返回 10 条结果</span></span>
<span class="line"><span>  Tokens: 输入 1500, 输出 200</span></span>
<span class="line"><span>  Duration: 2.3s</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[时间: 2024-01-15 10:30:04] [Agent: research] [Step: 2]</span></span>
<span class="line"><span>  Thought: 找到了 Anthropic 和 Google DeepMind 的信息</span></span>
<span class="line"><span>  Action: read_url(url=&quot;https://...&quot;)</span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Trace 的价值：调试（定位失败的具体步骤）、改进（分析成功和失败的模式）、审计（合规和安全审查）、成本分析（每个步骤的 Token 消耗）。</p><p>LangChain 的 Trace Analyzer Skill 把&quot;读日志找问题&quot;自动化：从 LangSmith 把所有运行轨迹拉下来，按批次切分启动多个分析子 Agent 并行跑，所有结论汇总成结构化的改进建议。</p>`,6)),(e(),r(A,null,{default:a(()=>[E(s,{id:"mermaid-47",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E8%BF%90%E8%A1%8C%5D%20--%3E%20B%5BTrace%20%E8%AE%B0%E5%BD%95%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%88%86%E6%9E%90%E5%A4%B1%E8%B4%A5%E6%A8%A1%E5%BC%8F%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%94%B9%E8%BF%9B%20Prompt%2F%E5%B7%A5%E5%85%B7%2F%E6%9E%B6%E6%9E%84%5D%0A%20%20%20%20D%20--%3E%20A%0A%20%20%20%20E%5B%E6%A8%A1%E5%BC%8F%E8%AF%86%E5%88%AB%5D%20--%3E%20F%5B%E5%93%AA%E4%BA%9B%E5%B7%A5%E5%85%B7%E7%BB%8F%E5%B8%B8%E8%A2%AB%E9%94%99%E8%AF%AF%E8%B0%83%E7%94%A8%EF%BC%9F%5D%0A%20%20%20%20E%20--%3E%20G%5B%E5%93%AA%E4%BA%9B%E6%AD%A5%E9%AA%A4%E7%BB%8F%E5%B8%B8%E5%A4%B1%E8%B4%A5%EF%BC%9F%5D%0A%20%20%20%20E%20--%3E%20H%5BAgent%E5%9C%A8%E5%93%AA%E9%87%8C%E9%99%B7%E5%85%A5%E5%BE%AA%E7%8E%AF%EF%BC%9F%5D%0A%20%20%20%20F%20--%3E%20C%0A%20%20%20%20G%20--%3E%20C%0A%20%20%20%20H%20--%3E%20C%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[l(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=n('<blockquote><p>💡 <strong>图解：</strong> Trace 不只是事后调试——它是实时改进的燃料，LangChain 靠这套闭环推了 13.7 分。</p></blockquote><h3 id="metrics-指标" tabindex="-1">Metrics（指标） <a class="header-anchor" href="#metrics-指标" aria-label="Permalink to &quot;Metrics（指标）&quot;">​</a></h3><p>聚合维度的量化数据——延迟、成本、成功率、Token 消耗。</p><p>关键指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th><th>为什么重要</th></tr></thead><tbody><tr><td><strong>Token 消耗/请求</strong></td><td>每次交互的成本</td><td>直接影响费用</td></tr><tr><td><strong>端到端延迟</strong></td><td>从输入到输出的时间</td><td>用户体验</td></tr><tr><td><strong>工具调用次数/任务</strong></td><td>Agent 执行效率</td><td>影响成本和延迟</td></tr><tr><td><strong>任务成功率</strong></td><td>完成率</td><td>核心业务指标</td></tr><tr><td><strong>KV 缓存命中率</strong></td><td>缓存效率</td><td>影响成本和延迟</td></tr><tr><td><strong>上下文利用率</strong></td><td>有效信息占比</td><td>影响输出质量</td></tr></tbody></table><p>按 Agent、按任务类型、按时间维度聚合。趋势比绝对值更重要——指标在改善还是恶化？</p><h3 id="logs-日志" tabindex="-1">Logs（日志） <a class="header-anchor" href="#logs-日志" aria-label="Permalink to &quot;Logs（日志）&quot;">​</a></h3><p>结构化的事件记录——工具调用、模型响应、错误信息、用户输入。</p><p>日志要结构化（JSON 格式便于查询）、要包含上下文（Session ID、Agent ID、Task ID）、要脱敏（PII 信息不要明文记录）。</p><hr><h2 id="trace-即反馈" tabindex="-1">Trace 即反馈 <a class="header-anchor" href="#trace-即反馈" aria-label="Permalink to &quot;Trace 即反馈&quot;">​</a></h2><p>Trace 不只是事后调试的工具，它是实时反馈的来源。</p><p><strong>诊断闭环</strong>：Agent 运行 → Trace 记录 → 分析失败模式 → 改进 Prompt/工具/架构 → 重新运行。LangChain 用这套闭环把 Agent 跑分提升了 13.7 分。</p><p><strong>模式识别</strong>：大量 Trace 中可以发现共性问题——哪些工具经常被错误调用？哪些步骤经常失败？Agent 在哪里容易陷入循环？</p><p><strong>成本优化</strong>：Trace 记录了每一步的 Token 消耗。分析哪些步骤消耗最多 Token，是否有优化空间——比如上下文注入减少探索、工具响应转文件减少重复传输。</p><hr><h2 id="实现实践" tabindex="-1">实现实践 <a class="header-anchor" href="#实现实践" aria-label="Permalink to &quot;实现实践&quot;">​</a></h2><h3 id="trace-记录" tabindex="-1">Trace 记录 <a class="header-anchor" href="#trace-记录" aria-label="Permalink to &quot;Trace 记录&quot;">​</a></h3><p>每次 LLM 调用和工具调用都记录 Trace。使用 OpenTelemetry 等标准格式，便于集成现有工具。Trace 数据存入时序数据库（如 ClickHouse）支持大规模查询。</p><h3 id="实时告警" tabindex="-1">实时告警 <a class="header-anchor" href="#实时告警" aria-label="Permalink to &quot;实时告警&quot;">​</a></h3><p>设置关键指标的告警阈值：Token 消耗突然飙升、成功率下降、延迟增大。告警渠道：Slack、邮件、PagerDuty。</p><h3 id="仪表板" tabindex="-1">仪表板 <a class="header-anchor" href="#仪表板" aria-label="Permalink to &quot;仪表板&quot;">​</a></h3><p>构建 Agent 专属仪表板：实时展示活跃 Agent 数量、Token 消耗趋势、成功率分布、常见失败模式。支持按时间、Agent、任务类型筛选。</p><hr><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">只监控 API 延迟</td><td style="text-align:left;">监控完整的 Agent Trace（工具调用链路）</td><td style="text-align:left;">API 延迟看不出 Agent 内部在做什么</td></tr><tr><td style="text-align:left;">日志只记录成功</td><td style="text-align:left;">同样详细记录失败和异常</td><td style="text-align:left;">失败信息是调试的关键线索</td></tr><tr><td style="text-align:left;">所有请求都全量 Trace</td><td style="text-align:left;">按重要性采样</td><td style="text-align:left;">全量 Trace 成本太高</td></tr><tr><td style="text-align:left;">没有异常告警</td><td style="text-align:left;">设置成功率、延迟、Token 消耗告警</td><td style="text-align:left;">没有告警 = 出了问题才知道</td></tr></tbody></table><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>三层架构：Trace（执行路径）+ Metrics（聚合指标）+ Logs（事件记录）</li><li>Trace 即反馈：诊断闭环、模式识别、成本优化</li><li>关键指标：Token 消耗、延迟、成功率、KV 缓存命中率</li><li>实践：结构化 Trace、实时告警、Agent 专属仪表板</li></ul><hr><p><strong>下一章</strong>: <a href="./02-安全与权限.html">安全与权限</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/06-Agent评估/">← 上一模块: Agent评估</a></p>',33))])}const F=o(d,[["render",B]]);export{m as __pageData,F as default};
